class PiyiCard extends StatelessWidget{const PiyiCard({super.key,required this.child,this.padding=const EdgeInsets.all(PiyiSpacing.md),this.margin,this.onTap});final Widget child;final EdgeInsetsGeometry padding;final EdgeInsetsGeometry? margin;final VoidCallback? onTap;@override Widget build(BuildContext context){final card=Container(margin:margin,decoration:BoxDecoration(color:Theme.of(context).colorScheme.surface,borderRadius:BorderRadius.circular(PiyiRadius.xl),boxShadow:PiyiShadows.card),child:Padding(padding:padding,child:child));if(onTap==null)return card;return Material(color:Colors.transparent,child:InkWell(borderRadius:BorderRadius.circular(PiyiRadius.xl),onTap:onTap,child:card));}}
